// 3rd Party
import {Link} from "react-router-dom";

// Local
import DefaultLayout from './DefaultLayout';
import "./css/Athletes.css";
import bioJson from "./athletes.json";
const rawBios = bioJson["athletes"];

function Athletes(props) {
    const alumni = props.alumni ?? false;

    const filteredBios = alumni ?
        rawBios.filter(pred => {console.log("A"); return pred.alum ?? false}) :
        rawBios.filter(pred => {console.log("B"); return !pred.alum ?? true}) ;

    const bios = filteredBios.map( function(raw, i) {
        console.log(raw.name);
        return (
                <div key={i} className="bio" >
                    <Link to={`/athlete/${raw.id}`}>
                        <img className="roster-image hover-transparent"
                            src={raw.image}
                            alt={raw.name}
                            height="200px"
                            width="200px"
                        />
                    </Link>
                    <h2 className="athlete-header">{raw.name}</h2>
                </div>
        );
    });

    const title = alumni ? "Alumni" : "Roster";


    return (
        <DefaultLayout>
            <h1 className="page-header">
                {title}
            </h1>
            <div className="bios-container horizontal-flex-container-wrapped">
                {bios}
            </div>
       </DefaultLayout>
    );
}

export default Athletes;